const fs = require('fs');
const path = require('path');

const rootDir = path.resolve(__dirname, '../../../');
const results = [];
const cli = args.cliName.toLowerCase();

function checkFile(filePath, pattern, label) {
  const fullPath = path.join(rootDir, filePath);
  if (!fs.existsSync(fullPath)) return results.push(`❌ ${label}: File not found (${filePath})`);
  const content = fs.readFileSync(fullPath, 'utf8');
  if (content.toLowerCase().includes(cli)) {
    results.push(`✅ ${label}: Found ${cli} in ${filePath}`);
  } else {
    results.push(`⚠️ ${label}: NOT found in ${filePath}`);
  }
}

// 1. Discovery
checkFile('server/src/terminal/commandRouter.ts', cli, 'Discovery Candidate');

// 2. Messaging Bridge
checkFile('server/src/terminal/messagingBridge.ts', cli, 'Messaging Bridge (@summon)');

// 3. Swarm Profile
const profilePath = path.join(rootDir, 'config/cli_profiles.json');
if (fs.existsSync(profilePath)) {
  const profiles = JSON.parse(fs.readFileSync(profilePath, 'utf8'));
  if (profiles[cli + '-cli'] || profiles[cli]) {
    results.push(`✅ Swarm Profile: Found in cli_profiles.json`);
  } else {
    results.push(`⚠️ Swarm Profile: NOT found in cli_profiles.json`);
  }
} else {
  checkFile('server/src/swarm/cliProfileManager.ts', cli, 'Swarm Profile (Source)');
}

// 4. Voice Session
checkFile('server/src/api/socketHandlers.ts', cli, 'Voice Session (Socket)');
checkFile('server/src/api/meetingRoom.ts', cli, 'Meeting Room (Orchestrator)');

return results.join('\n');
